+}
+
+impl ComposeValidationErrors {
+    const fn has_any(&self) -> bool {
+        self.to.is_some()
+            || self.cc.is_some()
+            || self.subject.is_some()
+            || self.thread_id.is_some()
+            || self.body.is_some()
+            || self.general.is_some()
